+
+    // Generate query vectors once
+    let queries = generate_random_vectors(100, PERCH_EMBEDDING_DIM);
+
+    for &size in &[SMALL_INDEX, MEDIUM_INDEX] {
+        // Build index
+        println!("Building index with {} vectors...", size);
