+        for vec in &vectors {
+            let quantized = quantizer.quantize(vec);
+            let dequantized = quantizer.dequantize(&quantized);
+
+            // Check that dequantized is close to original
+            let error: f32 = vec
+                .iter()
+                .zip(dequantized.iter())
+                .map(|(a, b)| (a - b).abs())
