+
+        // Random clustering should have low V-measure
+        let labels_random = vec![0, 1, 0, 1, 0, 1];
+        let (v_rand, _, _) = vm.compute(&labels_true, &labels_random);
+        assert!(v_rand < 0.5);
+    }
