+
+        // 0.5s tone
+        samples.extend(generate_sine_wave(1000.0, 0.5, sample_rate));
+
+        // 0.3s silence
+        samples.extend(vec![0.001f32; (sample_rate as f32 * 0.3) as usize]);
+
+        // 0.8s tone
+        samples.extend(generate_sine_wave(2000.0, 0.8, sample_rate));
