+        let segmenter = EnergySegmenter::new();
+        let recording_id = RecordingId::new();
+        let silence = vec![0.0f32; 32000];
+
+        let segments = segmenter.segment(&silence, 32000, recording_id).unwrap();
+        assert!(segments.is_empty());
