+/// Standard target sample rate for all processing (32 kHz).
+pub const TARGET_SAMPLE_RATE: u32 = 32_000;
+
+/// Standard segment duration for analysis (5 seconds).
+pub const STANDARD_SEGMENT_DURATION_MS: u64 = 5_000;
+
